// 极简版认证路由 - 完全绕过任何验证
import express from 'express';
import jwt from 'jsonwebtoken';

const router = express.Router();

// JWT密钥
const JWT_SECRET = process.env.JWT_SECRET || 'claw-secret-key-2026';

// 预定义用户
const users = {
  'admin@claw.com': {
    id: 'user-admin-001',
    name: '管理员',
    role: 'admin',
    plan: 'enterprise'
  },
  'user@claw.com': {
    id: 'user-demo-001',
    name: '演示用户',
    role: 'user',
    plan: 'premium'
  },
  'test@claw.com': {
    id: 'user-test-001',
    name: '测试用户',
    role: 'user',
    plan: 'basic'
  }
};

// 接受任何邮箱和密码
function acceptAnyLogin(email, password) {
  console.log(`🔧 [极简认证] 登录请求: ${email}, 密码: ${password}`);
  
  // 如果预定义用户存在，使用预定义信息
  if (users[email]) {
    return users[email];
  }
  
  // 否则创建新用户并保存到users对象
  const userId = 'user-' + Date.now();
  const newUser = {
    id: userId,
    name: email.split('@')[0] || '用户',
    role: email.includes('admin') ? 'admin' : 'user',
    plan: 'free'
  };
  
  // 保存到users对象，供profile端点使用
  users[email] = newUser;
  
  return newUser;
}

// POST /api/auth/login - 用户登录（极简版）
router.post('/login', (req, res) => {
  try {
    const { email, password } = req.body;

    console.log(`📧 登录请求: ${email}`);

    // 验证必填字段
    if (!email || !password) {
      return res.status(400).json({
        success: false,
        error: '邮箱和密码不能为空'
      });
    }

    // 接受任何登录
    const user = acceptAnyLogin(email, password);

    // 生成token
    const token = jwt.sign(
      { userId: user.id, email, role: user.role },
      JWT_SECRET,
      { expiresIn: '7d' }
    );

    res.status(200).json({
      success: true,
      message: '登录成功',
      data: {
        user: {
          id: user.id,
          email,
          name: user.name,
          role: user.role,
          plan: user.plan
        },
        token
      }
    });

  } catch (error) {
    console.error('登录错误:', error);
    res.status(500).json({
      success: false,
      error: '服务器错误'
    });
  }
});

// POST /api/auth/register - 用户注册（极简版）
router.post('/register', (req, res) => {
  try {
    const { email, password, name } = req.body;

    console.log(`📝 注册请求: ${email}`);

    // 验证必填字段
    if (!email || !password) {
      return res.status(400).json({
        success: false,
        error: '邮箱和密码不能为空'
      });
    }

    // 检查是否已存在（简单检查）
    if (users[email]) {
      return res.status(400).json({
        success: false,
        error: '该邮箱已被注册'
      });
    }

    // 创建新用户
    const userId = 'user-' + Date.now();
    const user = {
      id: userId,
      name: name || email.split('@')[0],
      role: 'user',
      plan: 'free'
    };

    // 添加到内存
    users[email] = user;

    // 生成token
    const token = jwt.sign(
      { userId, email, role: user.role },
      JWT_SECRET,
      { expiresIn: '7d' }
    );

    res.status(201).json({
      success: true,
      data: {
        user: {
          id: userId,
          email,
          name: user.name,
          role: user.role,
          plan: user.plan
        },
        token
      }
    });
  } catch (error) {
    console.error('注册错误:', error);
    res.status(500).json({
      success: false,
      error: '服务器错误'
    });
  }
});

// GET /api/auth/profile - 获取用户信息
router.get('/profile', (req, res) => {
  try {
    const authHeader = req.headers['authorization'];
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      return res.status(401).json({
        success: false,
        error: '未提供认证令牌'
      });
    }

    const token = authHeader.substring(7);
    try {
      const decoded = jwt.verify(token, JWT_SECRET);
      
      // 查找用户
      const user = users[decoded.email] || {
        id: decoded.userId,
        email: decoded.email,
        name: decoded.email.split('@')[0] || '用户',
        role: decoded.role || 'user',
        plan: 'free'
      };

      res.json({
        success: true,
        data: { user }
      });
    } catch (error) {
      res.status(401).json({
        success: false,
        error: '无效的令牌'
      });
    }
  } catch (error) {
    console.error('获取个人资料错误:', error);
    res.status(500).json({
      success: false,
      error: '服务器错误'
    });
  }
});

// GET /api/auth/test - 测试认证状态
router.get('/test', (req, res) => {
  res.json({
    success: true,
    data: {
      service: 'claw-auth',
      version: '1.0.0-min',
      status: 'active',
      mode: '极简认证（绕过数据库）',
      endpoints: [
        'POST /login - 接受任何邮箱/密码',
        'POST /register - 简化注册',
        'GET /profile - 令牌验证'
      ]
    }
  });
});

export default router;